<?php
namespace App\Http\Requests;
use Illuminate\Validation\Rule;
class SubscriberRequest extends TenantAwareRequest { public function authorize(): bool { return true; } public function rules(): array { $subscriber=$this->route('subscriber'); return ['type'=>['required',Rule::in(['person','company'])],'name'=>['required','string','max:180'],'document'=>['nullable','string','max:20',Rule::unique('subscribers','document')->where(fn($q)=>$q->where('tenant_id',$this->tenantId()))->ignore($subscriber?->id)],'email'=>['nullable','email','max:180'],'phone'=>['nullable','string','max:30'],'whatsapp'=>['nullable','string','max:30'],'zip_code'=>['nullable','string','max:12'],'street'=>['nullable','string','max:180'],'number'=>['nullable','string','max:30'],'complement'=>['nullable','string','max:100'],'district'=>['nullable','string','max:100'],'city'=>['nullable','string','max:100'],'state'=>['nullable','string','size:2'],'notes'=>['nullable','string'],'status'=>['required',Rule::in(['active','inactive','blocked'])]]; } }
